mapper.select:
select deviceId, deviceName, `state`, userId, autoClose
from store_device_v2
where userId = #{userId,jdbcType=VARCHAR}

    and `source` = #{source}

limit 1

mapper.update:
UPDATE store_device_v2
SET state  = #{state,jdbcType=TINYINT},
    userId = #{userId,jdbcType=BIGINT}
WHERE deviceId = #{deviceId,jdbcType=VARCHAR}

mapper.select:
SELECT d.*, s.storeName
FROM store_device_v2 as d
LEFT JOIN store as s on s.storeId = d.storeId
WHERE d.status = 1 and d.source in (301, 302)

    and d.storeId = #{store_id}

    
        AND d.storeId in (${storeIds})
    

    and d.deviceId = #{deviceId,jdbcType=VARCHAR}

ORDER BY d.id desc

    limit #{offset}, #{limit}

SELECT count(*)
FROM store_device_v2
WHERE status = 1 and source in (301, 302)

    and storeId = #{storeId}


    and deviceId = #{deviceId,jdbcType=VARCHAR}
